import React from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia} from '@shopify/react-native-skia';
import {useSharedValue, useFrameCallback, useDerivedValue} from 'react-native-reanimated';
export function BlobShape({size = 200, color = '#0A84FF'}: {size?: number; color?: string}) {
  const t = useSharedValue(0);
  useFrameCallback(({timeSinceFirstFrame}) => { t.value = timeSinceFirstFrame / 1000; });
  const path = useDerivedValue(() => { const p = Skia.Path.Make(); const cx = size/2; const cy = size/2; const r = size/2 - 10; const points = 8; for (let i = 0; i < points; i++) { const angle = (i / points) * Math.PI * 2; const wobble = Math.sin(t.value * 0.8 + i) * 10; const px = cx + Math.cos(angle) * (r + wobble); const py = cy + Math.sin(angle) * (r + wobble); if (i === 0) p.moveTo(px, py); else { const prevAngle = ((i-1) / points) * Math.PI * 2; const ctrlX = cx + Math.cos((angle + prevAngle)/2) * (r + wobble + 20); const ctrlY = cy + Math.sin((angle + prevAngle)/2) * (r + wobble + 20); p.quadTo(ctrlX, ctrlY, px, py); }} p.close(); return p; });
  return (<View style={{width: size, height: size}}><Canvas style={StyleSheet.absoluteFill}><Path path={path} color={color}/></Canvas></View>);
}

import React, {useCallback, useMemo, useState} from 'react';
import {StyleSheet, View, Text, Pressable, Image, FlatList} from 'react-native';
import * as ImagePicker from 'expo-image-picker';

type UploadItem = {id: string; uri: string; progress: number; status: 'queued' | 'uploading' | 'done' | 'failed'};
export function LivePhotoCaptureIOSWithMotion({upload}: {upload: (item: UploadItem, onProgress: (n: number) => void) => Promise<void>}) {
  const [items, setItems] = useState<UploadItem[]>([]);
  const pendingCount = useMemo(() => items.filter(i => i.status !== 'done').length, [items]);
  const pick = useCallback(async () => {
    const result = await ImagePicker.launchImageLibraryAsync({allowsMultipleSelection: true, quality: 0.82, mediaTypes: ImagePicker.MediaTypeOptions.All});
    if (result.canceled) return;
    const next = result.assets.map((asset) => ({id: asset.assetId ?? asset.uri, uri: asset.uri, progress: 0, status: 'queued' as const}));
    setItems((current) => [...current, ...next]);
    for (const item of next) {
      setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'uploading'} : i));
      try { await upload(item, (progress) => setItems((current) => current.map(i => i.id === item.id ? {...i, progress} : i))); setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'done', progress: 1} : i)); }
      catch { setItems((current) => current.map(i => i.id === item.id ? {...i, status: 'failed'} : i)); }
    }
  }, [upload]);
  return <View style={styles.wrap} accessibilityLabel="Live photo capture (iOS) with motion"><Pressable onPress={pick} accessibilityRole="button" accessibilityLabel="Choose media" style={styles.pick}><Text style={styles.pickText}>Add media</Text></Pressable><Text accessibilityLiveRegion="polite">{pendingCount} pending</Text><FlatList data={items} keyExtractor={(item) => item.id} numColumns={3} renderItem={({item}) => <View style={styles.tile}><Image source={{uri: item.uri}} style={styles.image} /><View style={[styles.progress, {width: `${Math.round(item.progress * 100)}%`}]} /><Text style={styles.badge}>{item.status}</Text></View>} /></View>;
}
const styles = StyleSheet.create({wrap: {gap: 12}, pick: {minHeight: 44, borderRadius: 12, alignItems: 'center', justifyContent: 'center', backgroundColor: '#111827'}, pickText: {color: 'white', fontWeight: '700'}, tile: {width: '33.33%', aspectRatio: 1, padding: 4}, image: {flex: 1, borderRadius: 12, backgroundColor: '#e5e7eb'}, progress: {position: 'absolute', left: 4, bottom: 4, height: 3, backgroundColor: '#22c55e'}, badge: {position: 'absolute', right: 8, bottom: 8, color: 'white', backgroundColor: 'rgba(0,0,0,0.55)', paddingHorizontal: 6, borderRadius: 8, overflow: 'hidden'}});
